INSERT INTO `prediction_markets` (`id`, `question`, `slug`, `rules`, `category_id`, `subcategory_id`, `condition_id`, `start_range_value`, `end_range_value`, `start_time`, `end_time`, `status`, `winning_outcome`, `trading_fee_percent`, `image`, `auto_generate_frequency`, `auto_generate_frequency_status`, `crypto_coin_id`, `tot_traded_val`, `last_yes_price`, `last_no_price`, `created_at`, `updated_at`) VALUES
(1, 'Will the Court Force Trump to Refund Tariffs?', 'Will the Court ', 'On May 28, 2025, the U.S. Court of International Trade ruled that Donald Trump exceeded his authority under the International Emergency Economic Powers Act (IEEPA) by imposing a series of broad tariffs. The ruling blocked several major measures, including the “Liberation Day” tariffs—a 10% tariff on all imports and country-specific rates of up to 50%—as well as additional tariffs targeting Canadian, Mexican, and Chinese goods. The Trump administration has filed a single consolidated appeal of this decision, titled V.O.S. Selections, Inc. v. United States.\\r\\n\\r\\nThis market will resolve to “Yes” if, by June 30, 2026, 11:59 PM ET, both of the following occur:\\r\\n\\r\\n1. The Trump administration’s appeal in V.O.S. Selections, Inc. v. United States is denied, in whole or in part\\r\\n\\r\\n2. U.S. importers receive refunds of at least some tariffs invalidated by the May 28, 2025 ruling, where such refunds occur as a consequence of the denial, in whole or in part, of the Trump administration’s appeal.\\r\\n\\r\\nOtherwise, this market will resolve to \\\"No\\\".\\r\\n\\r\\nAnnouncements, court orders, or plans to issue refunds will not be sufficient for resolution unless actual refunds are issued within the market timeframe.\\r\\n\\r\\nFor purposes of this market, a “refund” includes direct payments, credits, or offsets issued to importers by U.S. Customs and Border Protection or the U.S. Treasury reflecting repayment of previously collected tariffs.\\r\\n\\r\\nIf the appeal is fully upheld and no refunds are issued, this market will resolve to “No”.\\r\\n\\r\\nThe primary resolution source will be official government or court information, or a consensus of credible reporting.\\r\\n', 1, NULL, NULL, NULL, NULL, NULL, NULL, 'cancelled', NULL, 2.00, 'uploads/question/will-congress-pass-any-tariffs-by-march-31.svg', NULL, 1, NULL, 517.36, 0.5, 0.5, '2026-02-23 01:38:13', '2026-03-27 14:56:09'),
(3, 'Will Satoshi move any Bitcoin in 2026?', 'Will Satoshi', 'This market will resolve to “Yes” if any wallet labeled as belonging to Satoshi Nakamoto on Arkham’s Intel Explorer shows an “Outflow” or “Swaps” transaction at any time between January 9, 2026, 1:00 PM ET and December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No.”\\r\\n\\r\\nThe resolution source for this market is Arkham’s Intel Explorer, specifically the entity page for Satoshi Nakamoto available at https://intel.arkm.com/explorer/entity/satoshi-nakamoto\\r\\n\\r\\nIf Arkham becomes permanently unavailable, this market will resolve based on a consensus of credible sources.', 3, NULL, NULL, NULL, NULL, '2026-03-02 00:00:00', '2026-03-02 12:18:59', 'resolved', NULL, 2.00, 'uploads/coins/btc.svg', NULL, 1, 1, 744, 0.5, 0.5, '2026-02-23 01:38:13', '2026-03-19 14:45:19'),
(4, 'Will Satoshi move any Bitcoin in 2027?', 'move any Bitcoin', 'This market will resolve to “Yes” if any wallet labeled as belonging to Satoshi Nakamoto on Arkham’s Intel Explorer shows an “Outflow” or “Swaps” transaction at any time between January 9, 2026, 1:00 PM ET and December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No.”\r\n\r\nThe resolution source for this market is Arkham’s Intel Explorer, specifically the entity page for Satoshi Nakamoto available at https://intel.arkm.com/explorer/entity/satoshi-nakamoto\r\n\r\nIf Arkham becomes permanently unavailable, this market will resolve based on a consensus of credible sources.', 3, NULL, NULL, NULL, NULL, '2026-03-02 00:00:00', '2026-03-02 12:18:59', 'resolved', NULL, 2.00, 'uploads/coins/btc.svg', NULL, 1, 1, 877, 0.5, 0.5, '2026-02-24 10:25:07', '2026-03-19 14:44:44'),
(5, 'Bitcoin Up or Down on March 3?', 'March 3', 'This market will resolve to \"Up\" if the \"Close\" price for the Binance 1 minute candle for BTC/USDT Feb 26 \'26 12:00 in the ET timezone (noon) is lower than the final \"Close\" price for the Feb 27 \'26 12:00 ET candle.\n\nThis market will resolve to \"Down\" if the \"Close\" price for the Binance 1 minute candle for BTC/USDT Feb 26 \'26 12:00 in the ET timezone (noon) is higher than the final \"Close\" price for the Feb 27 \'26 12:00 ET candle.\n\nIf the final \"Close\" price for both of these candles is exactly equal on Binance, this market will resolve 50-50.\n\nThe resolution source for this market is Binance, specifically the BTC/USDT \"Close\" prices currently available at https://www.binance.com/en/trade/BTC_USDT with \"1m\" and \"Candles\" selected on the top bar.\n\nPlease note that this market is about the price according to Binance BTC/USDT, not according to other sources or spot markets.', 3, 2, NULL, NULL, 66282.3, '2026-03-02 00:00:00', '2026-03-02 12:18:59', 'resolved', 'yes', 1.00, 'uploads/coins/btc.svg', 'daily', 1, 1, 97618260, 0.5, 0.5, '2026-02-26 13:27:35', '2026-03-17 10:38:17'),
(6, 'Up or Down on Bitcoin in next 24 hours?', 'Bitcoin in next 24', 'If the price of Bitcoin is above 65407.2 after 24 hours, \"Yes\" wins. If it is below, \"No\" wins. Results will be based on the price at 2026-03-03 00:00:00. Winning result based on the bybit price feed.', 3, 2, NULL, NULL, 65407.2, '2026-03-02 13:58:20', '2026-03-03 00:00:00', 'resolved', 'no', 1.00, 'uploads/coins/btc.svg', 'daily', 1, 1, 96619544.82, 0.5, 0.5, '2026-03-02 13:58:20', '2026-03-20 15:23:38'),
(7, 'Up or Down on BTC in next 24 hours?', '', 'If the price of BTC is above  after 24 hours, \'Yes\' wins. If it is below, \'No\' wins. Results will be based on the price at 2026-03-10 00:00:00. Winning result based on the Bybit price feed.', 3, 2, 6, NULL, 700, '2026-03-09 14:29:39', '2026-03-10 00:00:00', 'resolved', 'no', 1.00, 'uploads/coins/btc.svg', 'daily', 1, 1, NULL, 0.5, 0.5, '2026-03-09 14:29:39', '2026-03-17 10:38:17'),
(8, 'Up or Down on BTC in next 24 hours?', 'btc-updown-daily-1773140592', 'If the price of BTC is above  after 24 hours, \'Yes\' wins. If it is below, \'No\' wins. Results will be based on the price at 2026-03-11 00:00:00. Winning result based on the Bybit price feed.', 3, 4, 7, NULL, 150000, '2026-03-10 11:03:12', '2026-03-11 00:00:00', 'resolved', 'yes', 1.00, 'uploads/coins/btc.svg', 'daily', 1, 1, NULL, 0.5, 0.5, '2026-03-10 11:03:12', '2026-03-17 10:38:17'),
(9, 'Will Crude Oil (CL) hit__ by end of March?', 'will-crude-oil-cl-hit-by-e', 'This market will resolve to \"Yes\" if, on any trading day, the official CME settlement price for the Active Month (front month) of Crude Oil (CL) futures is equal to or above the listed price by the final trading day of March 2026. Otherwise, the market will resolve to \"No\".\r\n\r\nFor CME Crude Oil (CL) futures contracts, the active month is the nearest of the contract months listed. The active month becomes a non-active month effective two business days prior to the spot month expiration. For example; if the spot month expires on a Friday the next listed contract will be considered the Active Month on the Wednesday prior to the spot month expiration.\r\n\r\nOnly the Active Month\'s official settlement price published by CME Group will be considered. Intraday trades, highs, lows, bids, offers, midpoint values, or indicative prices do not count.\r\n\r\nNote that the settlement price may differ from the last traded price. CME\'s methodology to determine the settlement price can vary by commodity and contract.\r\n\r\nOnly days on which CME publishes an official settlement price for the Active Month will be included. Days without settlement prices (weekends, holidays, or market closures) are ignored.\r\n\r\nThis market will resolve based on the settlement price as it appears on the CME settlement page at the time it is first published for that trading day, regardless of any later corrections or updates.\r\n\r\nThe resolution source for this market is the CME Group website — specifically, the daily \"Settlement\" price for the Active Month of Crude Oil (CL) futures.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/crude-oil.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-10 11:10:40', '2026-03-28 14:21:12'),
(10, 'Republican Presidential Nominee 2028', 'republican-presidential-nomine', 'This market will resolve to “Yes” if the named individual wins and accepts the 2028 nomination of the Republican Party for U.S. president. Otherwise, this market will resolve to “No”.\r\n\r\nThe resolution source for this market will be a consensus of official Republican Party sources.\r\n\r\nAny replacement of the Republican nominee before election day will not change the resolution of the market.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/republicans2028.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 05:03:08', '2026-03-23 06:16:13'),
(11, 'Presidential Election Winner 2028', 'presidential-election-winner-2', 'The 2028 US Presidential Election is scheduled to take place on November 7, 2028.\r\n\r\nThis market will resolve to the person who wins the 2028 US Presidential Election.\r\n\r\nThe resolution source for this market is the Associated Press, Fox News, and NBC. This market will resolve once all three sources call the race for the same candidate. If all three sources haven’t called the race for the same candidate by the inauguration date (January 20, 2029) this market will resolve based on who is inaugurated.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/presidential-election-winner-2024.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 05:31:34', '2026-03-23 06:16:07'),
(12, 'US x Iran ceasefire by...?', 'us-x-iran-ceasefire-by', 'This market will resolve to “Yes” if there is an official ceasefire agreement, defined as a publicly announced and mutually agreed halt in direct military engagement, between the United States and Iran by the listed date, 11:59 PM ET.\r\n\r\nFor the purposes of this market, an “official ceasefire agreement” requires clear public confirmation from both the United States government and the government of Iran that they have agreed to halt military hostilities against one another.\r\n\r\nIf the agreement is officially reached before the resolution date, this market will resolve to “Yes,” regardless of whether the ceasefire officially takes effect after the resolution date.\r\n\r\nAny form of informal understanding, backchannel communication, de-escalation without an announced agreement, or unilateral pause in hostilities will not be considered an official ceasefire. Humanitarian pauses, limited operational pauses, or temporary tactical stand-downs will not count toward the resolution of this market.\r\n\r\nA broader peace deal, normalization agreement, or political framework will qualify only if it includes a publicly announced and mutually agreed halt in military engagement between the United States and Iran, effective on a specified date, or otherwise confirmed by an overwhelming consensus of credible reporting. Agreements that outline future negotiations or de-escalation measures without an explicit, dated commitment to stop fighting will not qualify.\r\n\r\nThis market’s resolution will be based on official statements from the United States government and the government of Iran. However, a wide consensus of credible media reporting confirming that an official ceasefire agreement has been reached will suffice.', 1, 1, 3, NULL, NULL, NULL, NULL, 'cancelled', NULL, 1.00, 'uploads/question/us-x-iran-ceasefire-by.svg', NULL, 1, NULL, 10, 0.5, 0.5, '2026-03-11 05:34:22', '2026-03-28 10:23:48'),
(13, 'Elon Musk # tweets March 6 - March 13, 2026?', 'elon-musk-tweets-march-6-m', 'This market will resolve according to the number of times Elon Musk (@elonmusk), posts on X from March 6 12:00 PM ET to March 13, 2026 12:00 PM ET.\r\n\r\nFor the purposes of this market, only main feed posts, quote posts and reposts will count.\r\n\r\nReplies will NOT count towards the total - however, replies on the main feed such as https://x.com/elonmusk/status/1786073478711353576 will be counted by the tracker.\r\n\r\nDeleted posts will count as long as they remain available long enough to be captured by the tracker (~5 minutes).\r\n\r\nCommunity reposts which are not counted by the tracker not count toward the total.\r\n\r\nThe resolution source for this market is the \'Post Counter\' figure for posts found at https://xtracker.polymarket.com. Individual posts can be viewed by clicking \"Export Data\". If the tracker does not update correctly in accordance with the rules, X itself may be used as a secondary resolution source.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/elon-musk-of-tweets-nov-22-29.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 05:42:53', '2026-03-23 06:15:53'),
(14, 'Will the Iranian regime fall by March 31?', 'will-the-iranian-regime-fall-b', 'This market will resolve to \"Yes\" if the Islamic Republic of Iran’s current ruling regime is overthrown, collapsed, or otherwise ceases to govern by March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nThis requires a broad consensus of reporting indicating that core structures of the Islamic Republic (e.g. the office of the Supreme Leader, the Guardian Council, IRGC control under clerical authority) have been dissolved, incapacitated, or replaced by a fundamentally different governing system or otherwise lost de facto power over a majority of the population of Iran. This could occur via revolution, civil war, military coup, or voluntary abdication, but only qualifies if the Islamic Republic no longer exercises sovereign power.\r\n\r\nRoutine political events such as elections, reforms, or leadership succession do not qualify. Internal coups or power shifts that preserve the Islamic Republic’s core structures also do not qualify. Only a clear break in continuity—such as a new provisional government, revolutionary council, or constitution replacing the Islamic Republic will qualify.\r\n\r\nPartial loss of territory or challenges from rebel or exile groups will not qualify unless the Islamic Republic no longer administers the majority of the Iranian population within Iran.\r\n\r\nThe resolution source will be a consensus of credible reporting.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/canada-recession-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 06:31:21', '2026-03-23 06:15:46'),
(15, 'How many Tesla deliveries in Q1 2026?', 'how-many-tesla-deliveries-in-q', 'This market will resolve according to Tesla\'s announced total vehicle deliveries for Q1 2026.\r\n\r\nIf Tesla does not publish Q1 2026 delivery figures by May 31, 2026, 11:59 PM ET, this market will resolve to the lowest bracket.\r\n\r\nIf the reported value falls exactly between two brackets, this market will resolve to the higher range bracket.\r\n\r\nThe resolution source will be https://ir.tesla.com/press.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/tesla-deliveries.svg', NULL, 1, NULL, 338, 0.59, 0.41, '2026-03-11 07:30:05', '2026-03-23 07:54:57'),
(16, 'GPT-5.5 released by...?', 'gpt-55-released-by', 'This market will resolve to \"Yes\" if OpenAI\'s GPT-5.5 model is made available to the general public by the specified date (ET). Otherwise, this market will resolve to \"No.\"\r\n\r\nGPT-5.5 refers to a product explicitly named GPT-5.5, or a variant that is recognized as a direct successor to GPT-5.4, similar to the progression from GPT-5.1 to GPT-5.2. (e.g., GPT-5.6, GPT-5.7, etc would qualify toward a \"Yes\" resolution to this market)\r\n\r\nQualifying releases of task-specialized models (e.g., GPT-Codex/Transcribe), cost-efficiency variants (e.g., Nano/Mini), or reasoning models of the o-series family will count for this market. Products labeled as a new flagship generation GPT-6 or similar will NOT qualify.\r\n\r\nFor this market to resolve to \"Yes,\" a qualifying model must be launched and publicly accessible, including via open beta or open rolling waitlist signups. A closed beta or any form of private access will not suffice.\r\n\r\nThe release must be either clearly defined and publicly announced by OpenAI as being accessible to the general public or otherwise made publicly accessible and explicitly labeled within the company’s official website. Labeling errors, placeholder text, or version names displayed on the website that do not correspond to a model that is actually accessible to the general public will not qualify.\r\n\r\nThe primary resolution source for this market will be official information from OpenAI, with additional verification from a consensus of credible reporting.', 6, 8, 10, NULL, NULL, NULL, NULL, 'resolved', 'yes', 1.00, 'uploads/question/gpt-5-be-released.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:33:41', '2026-03-28 13:24:47'),
(17, 'Discord IPO Closing Market Cap', 'discord-ipo-closing-market-cap', 'This market will resolve based on Discord\'s market capitalization at the closing price on its first day of trading.\r\n\r\nIf no IPO occurs by June 30, 2026, 11:59 PM ET, the market will resolve to \"No IPO by June 30, 2026\".\r\n\r\nMarket capitalization expresses the monetary value of a company’s outstanding shares, stated in its pricing currency. It is calculated as the number of shares outstanding multiplied by the closing share price on the first trading day.\r\n\r\nIf the relevant value falls exactly between two brackets, then this market will resolve to the higher range bracket.\r\n\r\nResolution will be based on the primary exchange’s official listing page. In the event that the relevant figure is not displayed, another reliable source will be used.\r\n\r\nIn the event of an interruption in the course of the normal trading session on Discord’s first day of trading (e.g., a circuit breaker or half-day), the market will resolve according to the official closing price of the abbreviated session. If no such official closing price is published, the market will resolve according to the next trading day on which an official closing price is published, treating that as the first day of trading for purposes of this market.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/discord-ipo-closing-market-cap.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:34:29', '2026-03-23 06:15:26'),
(18, 'DeepSeek V4 released by...?', 'deepseek-v4-released-by', 'This market will resolve to \"Yes\" if the next DeepSeek V model is made available to the general public by March 15, 2026, at 11:59 PM ET. Otherwise, this market will resolve to \"No.\"\r\n\r\nIntermediate versions (e.g., DeepSeek-V3.5) will not count; however, versions such as DeepSeek V4 or V5 would count.\r\n\r\nFor this market to resolve to \"Yes,\" the next DeepSeek V model must be launched and publicly accessible, including via open beta or open rolling waitlist signups. A closed beta or any form of private access will not suffice. The release must be clearly defined and publicly announced by DeepSeek as being accessible to the general public.\r\n\r\nThe \"next DeepSeek V model\" refers to the next major release in the DeepSeek V series, explicitly named as such or clearly positioned as a successor to DeepSeek-V3.\r\n\r\nThe primary resolution source for this market will be official information from DeepSeek, with additional verification from a consensus of credible reporting.', 6, 8, 10, NULL, NULL, NULL, NULL, 'resolved', 'yes', 1.00, 'uploads/question/fb-banner.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:35:31', '2026-03-28 13:31:00'),
(19, 'Claude 5 released by…?', 'claude-5-released-by', 'This market will resolve to \"Yes\" if Anthropic\'s Claude 5 model is made available to the general public by March 15, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No.\"\r\n\r\nFor this market to resolve to \"Yes,\" Claude 5 must be launched and publicly accessible, including via open beta or open rolling waitlist signups. A closed beta or any form of private access will not suffice. The release must be clearly defined and publicly announced by Anthropic as being accessible to the general public.\r\n\r\nClaude 5 refers to a product explicitly named Claude 5 (e.g. Claude 5.0 would count), or one that is recognized as a successor to Claude 4, similar to the progression from Claude 2 to Claude 3. Products labeled as Claude 4.5 or similar will not count for this market\'s resolution.\r\n\r\nThe primary resolution source for this market will be official information from Anthropic, with additional verification from a consensus of credible reporting.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/claude-5-released.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:36:13', '2026-03-23 06:15:12'),
(20, 'OpenAI IPO closing market cap above ___ ?', 'openai-ipo-closing-market-cap', 'This market will resolve to “Yes” if the official closing price for OpenAI\'s market capitalization on its first trading day is above the listed value. Otherwise, it will resolve to “No”.\r\n\r\nIf no IPO occurs by December 31, 2027, 11:59 PM ET, this market will resolve to “No”.\r\n\r\nMarket capitalization is defined as the total number of outstanding shares multiplied by the closing share price on the first trading day.\r\n\r\nResolution will be based on the primary exchange’s official listing page. In the event that the relevant figure is not displayed, another reliable source will be used.\r\n\r\nIn the event of an interruption in the course of the normal trading session on OpenAI\'s first day of trading (e.g., a circuit breaker or half-day), the market will resolve according to the official closing price of the abbreviated session. If no such official closing price is published, the market will resolve according to the next trading day on which an official closing price is published, treating that as the first day of trading.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/openai-ipo-closing-market-cap.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:37:17', '2026-03-23 06:15:05'),
(21, 'ChatGPT Outage by March 15?', 'chatgpt-outage-by-march-15', 'This market will resolve to “Yes” if OpenAI\'s ChatGPT experiences any incident classified as \'Partial/Full Outage\' as of the time it is marked as “Resolved” by the listed date (ET). Otherwise, this market will resolve to “No”.\r\n\r\nOnly incidents listing ChatGPT under \'Affected components\' will be considered. Incidents labeled as affecting \'APIs,\' or \'Sora,\' but not ChatGPT, will have no bearing on the resolution of this market.\r\n\r\nClassifications of an incident while it is ongoing will have no bearing on the resolution of this market. Only classifications of events that are resolved will be considered.\r\n\r\nQualifying incidents include outages and other issues classified as \'Partial/Full Outage\' when they are resolved, during this market\'s above-specified timeframe.\r\n\r\nAn incident resolved outside this market’s timeframe will only qualify if ongoing at this market’s resolution time, in which case the market will remain open until that incident is marked as “Resolved,” and resolution will be based on the first impact classification thereafter, regardless of subsequent revisions or corrections.\r\n\r\nRevisions that upgrade an incident’s impact classification to \'Partial/Full Outage\' will qualify if the incident was resolved and the revision is published within this market’s timeframe.\r\n\r\nThe primary resolution source for this market will be official system status information published by OpenAI on status.openai.com; however, a consensus of credible reporting may also be used.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/openai-ipo-closing-market-cap.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:39:33', '2026-03-23 06:14:58'),
(22, 'ChatGPT out as #1 Free App in the US Apple App Store by...?', 'chatgpt-out-as-1-free-app-in', 'This market will resolve to \"Yes\" if ChatGPT is no longer the iOS app ranked #1 in the United States on the iPhone Apple App Store\'s overall Top Charts under \"Free Apps\" by the specified date, 11:59PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nIf ChatGPT is no longer the #1 free app in the US Apple App Store at any point before the listed date, 11:59PM ET, this market will immediately resolve to \"Yes\".\r\n\r\nTo find the overall chart, click \"Apps\" at the bottom of the US iOS App Store app, scroll down to \"Top Free Apps\" and click \"See All\". Then under \"Free Apps\" in the \"Top Charts\" section, you\'ll see the list that will be used as the resolution source to this market (https://apps.apple.com/us/charts/iphone).', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/openai-ipo-closing-market-cap.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:40:23', '2026-03-23 06:14:51'),
(23, 'Will Apple release a new product line before 2027?', 'will-apple-release-a-new-produ', 'This market will resolve to \"Yes\" if Apple publicly announces and launches a new product line by December 31, 2026, 11:59 PM ET. Otherwise this market will resolve to \"No\".\r\n\r\nA \"new product line\" is defined as a category of products Apple has not previously sold, rather than an iteration or update of an existing product. Examples of a new product line would include an Apple-branded home robot or gaming console, while a new iPhone, Mac, iPad, Apple Watch, or AirPods models would not qualify.\r\n\r\nThe resolution source will be official information from Apple.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-apple-release-a-new-product.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:41:17', '2026-03-23 06:14:44'),
(24, 'OpenAI receives federal backstop for infrastructure before July?', 'openai-receives-federal-backst', 'OpenAI Chief Financial Officer Sarah Friar recently suggested that OpenAI would be supportive of a government backstop for its investments in AI infrastructure including chips and data centers. Friar and Open AI Chief Executive Officer Sam Altman later backtracked on that statement. You can read more about that here: https://www.cnn.com/2025/11/06/tech/openai-backtracks-government-support-chip-investments.\r\n\r\nThis market will resolve to “Yes” if OpenAI or any financial lender or intermediary involved in providing debt financing to OpenAI receives a U.S. federal government backstop for any debt-transaction undertaken primarily for the benefit of OpenAI’s investments in AI infrastructure by June 30, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nA backstop is defined as any explicit or legally binding loan guarantee, insurance, or equivalent financial instrument through which the U.S. federal government assumes or commits to assume partial or full repayment risk on OpenAI debt.\r\n\r\nTax credits, depreciation benefits, or grants not tied to a specific debt transaction will not qualify.\r\n\r\nThe debt transaction which receives a government backstop must be primarily aimed at the development, building, or manufacturing of AI infrastructure.\r\n\r\nThe primary source of resolution will be information from Open AI and the United States Federal Government; however, a consensus of credible reporting may also be used.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/openai-ipo-closing-market-cap.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:42:40', '2026-03-23 06:14:37'),
(25, 'Which company has best AI model end of June?', 'which-company-has-best-ai-mode', 'This market will resolve according to the company which owns the model which has the highest arena score based off the Chatbot Arena LLM Leaderboard (https://lmarena.ai/) when the table under the \"Leaderboard\" tab is checked on June 30, 2026, 12:00 PM ET.\r\n\r\nResults from the \"Arena Score\" section on the Leaderboard tab of https://lmarena.ai/leaderboard/text with the style control off will be used to resolve this market.\r\n\r\nIf two models are tied for the top arena score at this market\'s check time, resolution will be based on whichever company\'s name, as it is described in this market group, comes first in alphabetical order (e.g., if both were tied, \"Google\" would resolve to \"Yes\", and \"xAI\" would resolve to \"No\")\r\n\r\nThe resolution source for this market is the Chatbot Arena LLM Leaderboard found at https://lmarena.ai/. If this resolution source is unavailable at check time, this market will remain open until the leaderboard comes back online and resolve based on the first check after it becomes available. If it becomes permanently unavailable, this market will resolve based on another resolution source.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/which-company-has-best-ai-model-end-of-september.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:48:26', '2026-03-23 06:14:30'),
(26, 'Largest IPO by market cap in 2026?', 'largest-ipo-by-market-cap-in-2', 'This market will resolve to the company that achieves the highest market capitalization in U.S. dollars based on the official closing price on its first trading day in 2026.\r\n\r\nThis market will resolve to a company that completes an Initial Public Offering (IPO) between January 1 and December 31, 2026, 11:59 PM ET.\r\n\r\nMarket capitalization is defined as the total number of outstanding shares multiplied by the closing share price on the first trading day.\r\n\r\nIf two or more companies have exactly equal highest closing market capitalizations, this market will resolve to the company whose listed name comes first alphabetically.\r\n\r\nResolution will be based on the primary exchange’s official listing page. In the event that the relevant figure is not displayed, another reliable source will be used.\r\n\r\nIn case the respective company\'s primary exchange’s official listing page does not report in U.S. dollars, it will be converted to U.S. dollars using the U.S. Federal Reserve Board’s H.10 foreign exchange reference rate for the relevant currency pair on the company’s first trading day (https://www.federalreserve.gov/releases/h10/). If no such rate is available for the relevant trading day, the most recent previously published rate will be used. If the relevant currency is not listed, another credible exchange rate source will be used.\r\n\r\nA listed company may resolve to \"No\" as soon as it becomes unable to complete an IPO, including due to acquisition, merger, or absorption by an entity that is already publicly traded.\r\n\r\nIn the event of an interruption in the course of the normal trading session on the respective companies’ first day of trading (e.g., a circuit breaker or half-day), the market will resolve according to the official closing price of the abbreviated session. If no such official closing price is published, the market will resolve according to the next trading day on which an official closing price is published, treating that as the first day of trading for purposes of this market.', 6, 8, 10, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/highest-ipo-market-cap-2026.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:49:28', '2026-03-23 06:14:24'),
(27, 'Will Iran close the Strait of Hormuz by...?', 'will-iran-close-the-strait-of', 'If Iran halts or severely restricts international maritime traffic through the Strait of Hormuz by March 31, 2026, 11:59 PM ET, this market will resolve to \"Yes\". Otherwise, this market will resolve to \"No\".\r\n\r\nThe primary resolution source for this market will be official governmental information, however a consensus of credible reporting will also be used.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-iran-close-the-strait-of-hormuz-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:53:17', '2026-03-23 06:14:17'),
(28, 'Iran strikes Israel on...?', 'iran-strikes-israel-on', 'This market will resolve to \"Yes\" if Iran initiates a drone, missile, or air strike on Israel’s soil on the listed date in Israel Time (GMT+2). Otherwise, this market will resolve to \"No\".\r\n\r\nFor the purposes of this market, a qualifying \"strike\" is defined as the use of aerial bombs, drones, or missiles (including cruise or ballistic missiles) launched by Iranian military forces that impact Israeli ground territory.\r\n\r\nA strike on any area within the terrestrial territory of Israel counts. Strikes within the West Bank or the Gaza Strip, will not be counted as Israel.\r\n\r\nOnly military actions by Iranian forces explicitly claimed by the Islamic Republic of Iran, or confirmed to have originated from Iranian territory will count toward the resolution of this market. Attacks by proxy forces (i.e. Hezbollah, Houthis, etc.) will not count toward the resolution of this market.\r\n\r\nMissiles or drones that are intercepted and surface-to-air missile strikes will not be sufficient for a \"Yes\" resolution, regardless of whether they land on Israeli territory or cause damage.\r\n\r\nActions such as artillery fire, small arms fire, FPV or ATGM strikes, ground incursions, naval shelling, cyberattacks, or other operations conducted by Iranian ground operatives will not qualify.\r\n\r\nThe primary resolution source will be official government/military statements (Israel or foreign), multilateral bodies (UN, etc.), or a consensus of credible reporting from major international media and national broadcasters/newspapers.\r\n\r\nIf the date/time of a strike cannot be confirmed by a consensus of credible reporting within 48 hours of this market\'s end date, it will resolve to \"No\" regardless of whether a strike was later confirmed to have taken place.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/iran-strikes-israel-on.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:54:35', '2026-03-23 06:14:10'),
(31, 'Who will be the next Prime Minister of Israel after the next election?', 'who-will-be-the-next-prime-min', 'Legislative elections are schedule to be held in Israel on October 27, 2026.\r\n\r\nThis market will resolve to the next individual who is officially appointed and sworn in as Prime Minister of Israel following the 2026 parliamentary election. If an election is called early, this market will immediately resolve to the individual who is officially appointed and sworn in after that election.\r\n\r\nTo count for resolution, the individual must be formally sworn in. Any interim or caretaker Prime Minister will not count toward the resolution of this market.\r\n\r\nIf no such Prime Minister is sworn in by December 31, 2027, 11:59 PM ET, this market will resolve to “Other”.\r\n\r\nThe primary resolution source for this market will be official information from the Government of Israel; however, a consensus of credible reporting may also be used.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/who-will-be-the-next-prime-minister-of-israel-after-the-2026-election.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 07:59:37', '2026-03-23 06:14:03'),
(32, 'Nobel Peace Prize Winner 2026', 'nobel-peace-prize-winner-2026', 'This market will resolve according to the winner of the 2026 Nobel Peace Prize, as announced by the Norwegian Nobel Committee.\r\n\r\nIf multiple listed individuals or entities jointly receive the prize, the market will resolve to a single winner. If Donald Trump, Volodymyr Zelenskyy, Benjamin Netanyahu, Vladimir Putin, or Elon Musk are among the recipients, the market will resolve to the highest-ranked among them in that exact order of precedence. If none of those five are among the winners and the prize is awarded jointly to at least one listed individual and at least one listed organization, the market will resolve in favor of the individual. If no prioritized individuals are among the winners and all listed recipients are of the same type (all individuals or all organizations), the market will resolve to the person whose last name, or the entity’s name, comes first in alphabetical order as listed in this market.\r\n\r\nIf no official announcement regarding the 2026 Nobel Peace Prize has been made by March 31, 2027, 11:59 PM ET, this market will resolve to \"Other.\"\r\n\r\nThe resolution source for this market will be the first official announcement from the Norwegian Nobel Committee.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/nobel-peace-prize-winner-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:03:26', '2026-03-23 06:13:57'),
(33, 'Venezuela leader end of 2026?', 'venezuela-leader-end-of-2026', 'This market will resolve to the individual who officially holds the position of the head of state of Venezuela on Dec 31, 2026 at 12 PM ET.\r\n\r\nFor the purposes of this market, \"officially holds\" refers to the individual that was formally appointed, confirmed (if confirmation is required), and sworn in as the head of state of Venezuela or otherwise confirmed by official government information as being the head of state of Venezuela.\r\n\r\nIf the Venezuelan government does not clearly state who is the head of state, the market will resolve to the individual who is listed as the Head of State by the UN (see: https://www.un.org/dgacm/en/content/protocol/hshgnfa.\r\n\r\nIn the event that more than one official head of state is listed by the Venezuelan government, this market will resolve to the individual who is listed as having primary status. If no distinction is made, the market will resolve to the individual who first assumed the position.\r\n\r\nIf no individual holds the position this market will resolve to “No Head of State”.\r\n\r\nThe following do NOT constitute \"officially holding\" the role: nominated, announced, or designated as the head of state of Venezuela but appointment not yet effective; appointed with an effective date after Dec 31, 2026; previously served as the head of state of Venezuela but term has expired, resigned, or been terminated before Dec 31, 2026; serving as the head of state of Venezuela in a consultant, contractor, or unofficial capacity; named as successor or heir apparent to the head of state of Venezuela but not yet appointed; or holding a different role with oversight of the head of state of Venezuela but not the specified position itself.\r\n\r\nThe primary resolution source will be official information from the UN recognized government of Venezuela. If the Government of Venezuela does not clearly state who is the head of state, information from the UN and a consensus of credible reporting may be used.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/venezuela-leader-end-of-2026.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:04:26', '2026-03-23 06:13:50'),
(34, 'How many different countries will Israel strike in 2026?', 'how-many-different-countries-w', 'This market will resolve according to the total number of different countries\' soil that Israel initiates a drone, missile, or air strike between January 1, 2026, 12:00 AM ET and December 31, 2026, 11:59 PM ET.\r\n\r\nStrikes on embassies or consulates will count towards the country the embassy or consulate is located in, not towards the country they represent.\r\n\r\nStrikes within the territory controlled by Israel as of December 31, 2025, 11:59 PM ET, as well as strikes within the West Bank or the Gaza Strip, will not be counted towards this market\'s resolution.\r\n\r\nFor the purposes of this market, a qualifying \"strike\" is defined as the use of aerial bombs, drones, or missiles (including cruise or ballistic missiles) launched by Israeli military forces that impact another country\'s ground territory that is officially acknowledged by the Israeli government or a consensus of credible reporting.\r\n\r\nMissiles or drones that are intercepted and surface-to-air missile strikes will not count towards the resolution of this market, regardless of whether they land on another country\'s territory or cause damage.\r\n\r\nActions such as artillery fire, small arms fire, FPV or ATGM strikes directly, ground incursions, naval shelling, cyberattacks, or other operations conducted by Israeli ground operatives will not qualify.\r\n\r\nThe resolution source will be a consensus of credible reporting.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/israel-pops-off.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:05:27', '2026-03-23 06:13:43'),
(35, 'Will Israel launch a major ground offensive in Lebanon by March 31?', 'will-israel-launch-a-major-gro', 'This market will resolve to \"Yes\" if Israel initiates a major ground offensive in Lebanon by March 31, 2026, 11:59PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nA \"major ground offensive\" is defined as a large-scale military operation that involves more than 1,000 Israeli ground forces entering Lebanese territory that was not under Israeli control at the start of the offensive. This excludes smaller raids, special operations, or limited incursions directly bordering buffer zones already under Israeli control.\r\n\r\nThe resolution source will be a consensus of credible reporting.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-israel-launch-a-major-ground-offensive-in-lebanon-by-december-31.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:06:46', '2026-03-23 06:13:37'),
(36, 'Iran leader end of 2026?', 'iran-leader-end-of-2026', 'This market will resolve to the individual who de facto holds and exercises the powers of the head of state of the Islamic Republic of Iran on December 31, 2026 at 12:00 PM ET.\r\n\r\nFor the purposes of this market, “de facto holds” refers to the individual who exercises primary governing authority over the Iranian state at that time, including effective control over the armed forces, national institutions, and core executive decision-making, regardless of formal title, constitutional designation, or international recognition.\r\n\r\nFormal appointment, recognition by the United Nations, or recognition by foreign governments is not required.\r\n\r\nIf more than one individual claims to be head of state, this market will resolve to the individual who demonstrably exercises primary governing control within Iran’s territory at the specified time.\r\n\r\nIndicators of de facto authority may include control over the armed forces and security services; control over executive ministries and state administrative institutions; enforcement of national laws; issuance of binding national directives; and effective control over the capital and core state infrastructure.\r\n\r\nSymbolic status, foreign recognition without domestic control, nomination without effective authority, or expired prior service will not qualify.\r\n\r\nIf no individual exercises effective governing control at the specified time, this market will resolve to “No Head of State”.\r\n\r\nThe primary resolution source will be a consensus of credible reporting assessing who exercises effective governing authority at the specified time.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/khamenei-out-as-supreme-leader-of-iran-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:07:50', '2026-03-23 06:13:30'),
(37, 'NATO x Russia military clash by...?', 'nato-x-russia-military-clash-b', 'This market will resolve to \"Yes\" if there is a military encounter between the military forces of a NATO country and Russia between October 8, and March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nA \"military encounter\" is defined as any incident involving the use of force such as missile strikes, artillery fire, exchange of gunfire, or other forms of direct military engagement between NATO and Russian military forces. Non-violent actions, such as airspace violations, firing of warning shots (such as the June, 2021 Black Sea Confrontations between Russian forces and HMS Defender), or cyberattacks will not qualify.\r\n\r\nInterception of missiles or other one-way attack or loitering munitions (e.g. Shahed drones) which are targeting a 3rd party other than the listed countries or their respective forces will not alone qualify. Shooting down UAVs which are not munitions (e.g. MQ-9, Orlan 10, Orion, Bayraktar TB2, etc.) will qualify.\r\n\r\nIntentional physical collisions, including aerial interceptions and naval ramming without the direct use of weaponry, such as the 2023 Black Sea incident—where a Russian Su-27 damaged a U.S. MQ-9 Reaper drone\'s propeller, leading to its crash— will not qualify regardless of damage.\r\n\r\nMilitary contractors will qualify only if confirmed to be operating under the direct command or coordination of the respective state’s armed forces (e.g. the Battle of Khasham would not qualify).\r\n\r\nThe resolution source for this market will be a consensus of credible reporting.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/nato-x-russia-military-clash-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:08:48', '2026-03-23 06:13:24'),
(38, 'Will China invade Taiwan by end of 2026?', 'will-china-invade-taiwan-by-en', 'This market will resolve to \"Yes\" if China commences a military offensive intended to establish control over any portion of the Republic of China (Taiwan) by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nTerritory under the administration of the Republic of China including any inhabited islands will qualify, however uninhabited islands will not qualify.\r\n\r\nThe resolution source for this market will be will be official confirmation by China, Taiwan, the United Nations, or any permanent member of the UN Security Council, however a consensus of credible reporting will also be used.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/china-invades-taiwan-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:09:43', '2026-03-23 06:13:17'),
(39, 'Will Zelenskyy talk to Putin by...?', 'will-zelenskyy-talk-to-putin-b', 'This market will resolve to \"Yes\" if Volodymyr Zelenskyy and Vladimir Putin talk by March 31, 2026, 11:59 PM ET. Otherwise, it will resolve to \"No\".\r\n\r\nA talk is defined as any interaction between Volodymyr Zelenskyy and Vladimir Putin, occurring either in person or through verbal communication by phone or video call.\r\n\r\nEvents that occurred prior to the start of this market will not qualify toward its resolution.\r\n\r\nThe resolution source will be a consensus of credible reporting.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-zelenskyy-talk-to-putin-by-november-30.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:11:15', '2026-03-23 06:13:10'),
(40, 'Trump out as President before 2027?', 'trump-out-as-president-before', 'This market will resolve to “Yes” if Donald Trump resigns or is removed as President or otherwise ceases to be the President of the United States for any period of time by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nAn announcement of Donald Trump\'s resignation/removal before this market\'s end date will immediately resolve this market to \"Yes\", regardless of when the announced resignation/removal goes into effect.\r\n\r\nOnly permanent removal from office will qualify. Temporary removal (e.g. temporary invocation of the 25th Amendment under Section 3 or a Section 4 invocation not sustained by both Houses of Congress) or impeachment without removal will not count.\r\n\r\nA sustained invocation of the Twenty-Fifth Amendment, Section 4 (i.e., if both Houses of Congress, by two-thirds vote, uphold the Vice President and Cabinet’s determination of presidential inability) will qualify for a \"Yes\" resolution.\r\n\r\nThe resolution source for this market will be a consensus of credible reporting.', 5, 7, 8, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/trump-out-as-president-by-march-31.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:12:06', '2026-03-23 06:13:04'),
(41, '3rd largest company end of March?', '3rd-largest-company-end-of-mar', 'This market will resolve to the third-largest company in the world by market cap on March 31, 2026, as of market close.\r\n\r\nThe resolution source for this market will be a consensus of credible reporting.', 4, 6, 5, NULL, NULL, NULL, NULL, 'cancelled', NULL, 1.00, 'uploads/question/largest-company-eoy.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:21:31', '2026-03-27 05:29:54');
INSERT INTO `prediction_markets` (`id`, `question`, `slug`, `rules`, `category_id`, `subcategory_id`, `condition_id`, `start_range_value`, `end_range_value`, `start_time`, `end_time`, `status`, `winning_outcome`, `trading_fee_percent`, `image`, `auto_generate_frequency`, `auto_generate_frequency_status`, `crypto_coin_id`, `tot_traded_val`, `last_yes_price`, `last_no_price`, `created_at`, `updated_at`) VALUES
(42, 'How many Fed rate cuts in 2026?', 'how-many-fed-rate-cuts-in-2026', 'This market will resolve according to the exact amount of cuts of 25 basis points in 2026 by the Fed (including any cuts made during the December meeting).\r\n\r\nEmergency rate cuts outside of scheduled FOMC meetings will also count toward the total number of cuts in 2026. This market will remain open until December 31, 2026, 11:59 PM ET, to account for any such emergency actions.\r\n\r\nFor example, if the Fed cuts rates by 50 bps after a meeting, it would be considered 2 cuts (of 25 bps each).\r\n\r\nThis market will resolve early to \"No\" if the specified number of cuts becomes impossible — i.e., if more cuts have already occurred than the strike in question.\r\n\r\nNote that cuts between 1–24 bps (inclusive) will also be considered 1 rate cut.\r\n\r\nThe resolution source for this market will be FOMC statements after meetings scheduled in 2026 according to the official calendar: https://www.federalreserve.gov/monetarypolicy/fomccalendars.htm. The level and change of the target federal funds rate is also published at the official website of the Federal Reserve at https://www.federalreserve.gov/monetarypolicy/openmarket.htm.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/how-many-fed-rate-cuts-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:23:05', '2026-03-23 06:12:49'),
(43, 'How high will US unemployment go in 2026?', 'how-high-will-us-unemployment', 'This market will resolve to “Yes” if any seasonally adjusted unemployment rate (total unemployed, as a percent of the civilian labor force, official unemployment rate denoted as U-3) reported by the Bureau of Labor Statistics in an “Employment Situation Report” for a reference month in 2026 is greater than or equal to the listed percentage. Otherwise, this market will resolve to “No”.\r\n\r\nThe relevant reports for this market are the Employment Situation Reports for January-December, 2026. This market may not resolve to “No” until the Employment Situation report for December 2026 is released. If no Employment Situation Report for December 2026 is released by March 31, 2027, 11:59 PM ET, however, this market will resolve based on all previously published data up to that time.\r\n\r\nThe resolution source for this market is the Monthly Employment Situation Report, published by the BLS every month at https://www.bls.gov/bls/news-release/empsit.htm, specifically the U-3 measure in Table A-15 for each month.\r\n\r\nNote: the resolution source for this market reports unemployment to one decimal point. Thus, this is the level of precision that will be used when resolving the market.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/march-unemployment-rate.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:24:03', '2026-03-23 06:12:42'),
(44, 'Canada recession before 2027?', 'canada-recession-before-2027', 'This market will resolve to “Yes”, if either of the following conditions are met:\r\n\r\n1. The C.D. Howe Institute’s Business Cycle Council publicly announces that a recession has occurred in Canada, at any point before 2027, with the announcement made by December 31, 2026, 11:59 PM ET.\r\n\r\n2. The seasonally adjusted annualized percent change in quarterly Canadian Real GDP (expenditure-based), chained (2017) dollars GDP from the previous quarter is less than 0.0 for two consecutive quarters between Q4 2025 and Q4 2026 (inclusive), as reported by Statistics Canada (StatCan).\r\n\r\nOtherwise, this market will resolve to \"No\".\r\n\r\nNote that any two consecutive, concurrent vintages indicating negative GDP growth will qualify, regardless of prior or later revisions. For example, if upon release, the initial estimate for Q2 2026 was negative, and Q1 2026\'s most recent, up-to-date estimate was also negative, this market would resolve to \"Yes\". If on December 31, 2026 the latest estimate for quarterly GDP in Q3 2026 was negative, this market will stay open until Statistics Canada publishes the initial estimate for Q4 2026, at which point it will resolve to \"Yes\" if Q4 2026 was negative or if the C.D. Howe Institute’s Business Cycle Council declares a recession by then.\r\n\r\nThe resolution source will be the official announcements from the C.D. Howe Institute’s Business Cycle Council and Statistics Canada’s estimate of seasonally adjusted annualized percent change in quarterly Canadian real GDP from previous quarters as released by Statistics Canada (e.g., as reported in the line “Gross domestic product at market prices” in Table 3 of the quarterly GDP release: https://www150.statcan.gc.ca/n1/daily-quotidien/250829/t003a-eng.htm)', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/canada-recession-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:26:17', '2026-03-23 06:12:35'),
(45, 'Will Trump sue Powell by March 31?', 'will-trump-sue-powell-by-march', 'This market will resolve to \"Yes\" if Donald Trump, his administration (including any executive branch department, agency, or office), or the United States federal government files a lawsuit against Jerome Powell, in his personal or official capacity, by March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nThe lawsuit must be filed in a U.S. federal or state court and must name Jerome Powell as a defendant.\r\n\r\nAn announcement of a lawsuit will NOT qualify for a “Yes” resolution; a lawsuit must actually be filed.\r\n\r\nThe primary resolution sources for this market will be official information from the relevant U.S. federal court. However, a consensus of credible reporting may also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/trump-out-as-president-by-march-31.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:27:24', '2026-03-23 06:12:28'),
(46, 'Major U.S. bank bailout before 2027?', 'major-us-bank-bailout-before', 'This market will resolve to \"Yes\" if a U.S. bank with total assets exceeding $50 billion as of November 11, 2025 (see:https://www.federalreserve.gov/releases/lbr/current/), is bailed out by the U.S. federal government by December 31, 2026, 11:59 PM ET. Otherwise this market will resolve to “No”.\r\n\r\nA bailout is defined as any of these actions in direct response to directly related to solvency, liquidity, or capital adequacy concerns.\r\n\r\n-Establishing a Federal Reserve emergency lending facility\r\n-Creating an FDIC-assisted resolution or bridge bank\r\n-A U.S. Treasury capital injection\r\n-A publicly disclosed, regulatory-facilitated acquisition\r\n\r\nAn official announcement from the U.S. government that they are taking any of these actions will qualify regardless of if/when the action occurs.\r\n\r\nRoutine access to standing facilities (such as the discount window or BTFP) or participation in stress tests, capital raises, or ordinary supervision will not on their own qualify.\r\n\r\nIf a bank experiences distress but is acquired privately without public intervention or coordination, this will not qualify.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/major-us-bank-bailout-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:28:23', '2026-03-23 06:12:21'),
(47, 'Will Trump cut corporate taxes before 2027?', 'will-trump-cut-corporate-taxes', 'This market will resolve to \"Yes\" if Donald J. Trump, as President of the United States, signs into law a bill that lowers the corporate tax rate in the United States below 21% at any point by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No.\"\r\n\r\nNote that the cut does not need to go into effect before the resolution date - it just needs to be signed into law by then.\r\n\r\nThis market\'s primary resolution source will be official information from the Trump administration, however a consensus of credible information will also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-trump-cut-corporate-taxes-in-2025.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:30:23', '2026-03-23 06:12:13'),
(48, 'Any EU nation\'s debt downgraded before 2027?', 'any-eu-nations-debt-downgrade', 'This market will resolve to \"Yes\" if the long-term sovereign credit letter rating of any European Union member country is downgraded by any of the three major credit rating agencies (S&P, Moody\'s, Fitch) at any point between the date of market creation and December 31, 2026 11:59pm ET. Otherwise, this market will resolve to \"No\".\r\n\r\nThe resolution source for this market will be official information from Standard & Poor\'s, Moody\'s, or Fitch, however a consensus of credible reporting will also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/who-will-be-the-next-prime-minister-of-israel-after-the-2026-election.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:31:58', '2026-03-23 06:12:07'),
(49, 'US Treasury transactions on blockchain by June 30?', 'us-treasury-transactions-on-bl', 'This market will resolve to \"Yes\" if the US Department of the Treasury sends any funds or assets via a blockchain by June 30, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nFor this market to resolve to \"Yes\", the payment must be a publicly announced, official transaction involving the sending of assets or funds; exploratory or experimental transactions will not count toward the resolution of this market.\r\n\r\nThe primary resolution source for this market will be official information from the government of the United States, however a consensus of credible reporting will also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/coins/btc.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:33:05', '2026-03-23 06:11:59'),
(50, 'Will Congress pass any tariffs by March 31?', 'will-congress-pass-any-tariffs', 'This market will resolve to \"Yes\" if both the U.S. House of Representatives and the U.S. Senate pass the same bill, measure, or resolution that explicitly seeks to create a tariff on any country or set of countries for any goods by March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No.\"\r\n\r\nA bill, measure or resolution will be considered to “seek to create a tariff” if it explicitly calls for or orders the imposition of any import tax or duty on any category of goods from any country or region. Category-specific tariffs, general tariffs on countries, or blanket global tariffs will all qualify. The delegation of tariff powers to other government authorities (e.g. the President) without calling for specific tariffs to be imposed, trade restrictions which do not impose an import tax or duty, or tariffs imposed under existing executive authority without new passage by both chambers of Congress will not qualify.\r\n\r\nA measure amended by either chamber will only qualify if the amended version is subsequently passed by both chambers in identical form.\r\n\r\nThe resolution source will be official congressional voting records and a consensus of credible reporting.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-congress-pass-any-tariffs-by-march-31.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:41:09', '2026-03-23 06:11:52'),
(51, 'Will the Court Force Trump to Refund Tariffs?', 'will-the-court-force-trump-to', 'On May 28, 2025, the U.S. Court of International Trade ruled that Donald Trump exceeded his authority under the International Emergency Economic Powers Act (IEEPA) by imposing a series of broad tariffs. The ruling blocked several major measures, including the “Liberation Day” tariffs—a 10% tariff on all imports and country-specific rates of up to 50%—as well as additional tariffs targeting Canadian, Mexican, and Chinese goods. The Trump administration has filed a single consolidated appeal of this decision, titled V.O.S. Selections, Inc. v. United States.\r\n\r\nThis market will resolve to “Yes” if, by June 30, 2026, 11:59 PM ET, both of the following occur:\r\n\r\n1. The Trump administration’s appeal in V.O.S. Selections, Inc. v. United States is denied, in whole or in part\r\n\r\n2. U.S. importers receive refunds of at least some tariffs invalidated by the May 28, 2025 ruling, where such refunds occur as a consequence of the denial, in whole or in part, of the Trump administration’s appeal.\r\n\r\nOtherwise, this market will resolve to \"No\".\r\n\r\nAnnouncements, court orders, or plans to issue refunds will not be sufficient for resolution unless actual refunds are issued within the market timeframe.\r\n\r\nFor purposes of this market, a “refund” includes direct payments, credits, or offsets issued to importers by U.S. Customs and Border Protection or the U.S. Treasury reflecting repayment of previously collected tariffs.\r\n\r\nIf the appeal is fully upheld and no refunds are issued, this market will resolve to “No”.\r\n\r\nThe primary resolution source will be official government or court information, or a consensus of credible reporting.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-the-court-force-trump-to-refund-tariffs-2026-06-30.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:42:14', '2026-03-23 06:11:45'),
(52, 'Will a 10% US blanket tariff be in effect on March 31?', 'will-a-10-us-blanket-tariff-b', 'This market will resolve to “Yes” if a general or blanket US tariff of 10% or more on imports into the United States is in effect on March 31, 2026 at 12:00 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nA general or blanket tariff is a tariff policy that applies a baseline tariff rate of 10% or greater to imports broadly, rather than being limited to a narrow set of products or countries. A tariff that includes item-specific, country-specific, or other limited exceptions will still qualify, as long as a baseline policy of a 10% or greater tariff on imports into the United States is in effect at the specified time.\r\n\r\n“In effect\" means the tariff must be operational in its application to US imports at the specified time. General or blanket tariffs which go into effect, but are then blocked, injuncted, repealed, or otherwise invalidated such that a blanket tariff rate of 10% or more is not being imposed on imports into the United States at this market’s resolution time will not count.\r\n\r\nThis market\'s primary resolution source will be official information from the United States federal government; however, a consensus of credible information may also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-a-10-us-blanket-tariff-be-in-effect-on-march-31.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 09:43:07', '2026-03-23 06:11:38'),
(53, 'Will Trump cut off trade with Spain?', 'will-trump-cut-off-trade-with', 'This market will resolve to “Yes” if Donald Trump signs any federal legislation into law or performs any executive action (including executive orders, proclamations, and memoranda) that orders, directs, or enacts a comprehensive ban on imports and exports between the United States and Spain by March 31, 2026, 11:59 PM ET. Otherwise this market will resolve to “No”.\r\n\r\nAn official announcement, made within this market’s timeframe, from the Trump Administration that a concrete policy to comprehensively ban imports and exports between the US and Spain will definitively be implemented, without such legislation or executive action, will also suffice for a “Yes” resolution. Such an announcement must be tied to a specific policy or set of actions being implemented; mere public statements that a ban will be implemented will not qualify.\r\n\r\nA comprehensive ban on imports and exports between the United States and Spain is defined as any trade ban or embargo that applies broadly to imports and exports between the US and Spain. Limited exceptions for certain categories of imports and exports will not disqualify a ban from counting, provided the ban applies generally to US-Spain imports and exports. Bans or embargoes which apply only to a limited subset of U.S.-Spain trade, or tariffs, sanctions, or other punitive trade measures which do not constitute a comprehensive ban on imports or exports between the US and Spain, will not count.\r\n\r\nA qualifying ban which is ordered, enacted, or announced within this market’s timeframe will qualify, regardless of when it is scheduled to be implemented or if it is blocked or invalidated prior to implementation.\r\n\r\nThe primary resolution source for this market will be official information from the Trump Administration; however, a consensus of credible reporting may also be used.', 4, 6, 5, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-trump-cut-off-trade-with-spain.svg', NULL, 1, NULL, 57, 0.5, 0.5, '2026-03-11 09:44:07', '2026-03-23 06:11:32'),
(54, 'Any Brazil STF Justice removed by impeachment before 2027?', 'any-brazil-stf-justice-removed', 'This market will resolve to “Yes” if any justice of the Brazil Supreme Federal Court (STF) is permanently removed from the court as a result of impeachment or a trial for a crime of responsibility by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nJustices leaving the court due to term limits, voluntary resignation, or any other reason not resulting from impeachment or a trial for a crime of responsibility will not count.\r\n\r\nImpeachments, trials for crimes of responsibility, suspensions, or other procedural measures will not alone suffice to resolve this market if they do not result in the permanent removal of a justice from the Brazil Supreme Federal Court.\r\n\r\nThe primary resolution source for this market will be official information from the government of Brazil; however, a consensus of credible reporting may also be used.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/any-brazil-supreme-court-justice-removed-via-impeachment-before-2027-l8Doj_dSYurm.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:00:39', '2026-03-23 06:11:25'),
(55, 'Alexandre de Moraes out as Brazil Supreme Court Justice?', 'alexandre-de-moraes-out-as-bra', 'This market will resolve to “Yes” if Alexandre de Moraes ceases to be a Justice of Brazil’s Supreme Federal Court for any period of time between market creation and December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nAn announcement of Alexandre de Moraes\'s resignation/removal before this market\'s end date will immediately resolve this market to \"Yes\", regardless of when the announced resignation/removal goes into effect.\r\n\r\nThe resolution source for this market will be official information from Alexandre de Moraes and the government of Brazil; however, a consensus of credible reporting may also be used.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/alexandre-de-moraes-out-as-brazil-supreme-court-justice-nbO5Z_3RToLt.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:01:37', '2026-03-23 06:11:18'),
(56, 'Will any candidate win the Texas Republican Senate Primary outright?', 'will-any-candidate-win-the-tex', 'Primary elections in Texas are scheduled to be held on March 3, 2026, with a runoff on May 26 if no candidate receives a majority.\r\n\r\nThis market will resolve to \"Yes\" if any candidate wins this election in the first round, i.e., obtains an outright majority. Otherwise, this market will resolve to \"No\".\r\n\r\nIf the results of the specified election are not known definitively by November 30, 2026, 11:59 PM ET, this market will resolve 50-50.\r\n\r\nThe primary resolution source for this market will be information from the State of Texas; however, a consensus of credible reporting will also be used.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/texas-flag-map-market-a5dc3bc9de.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:02:43', '2026-03-23 06:11:12'),
(57, 'Will China unban Bitcoin by 2027?', 'will-china-unban-bitcoin-by-20', 'This market will resolve to \"Yes\" if the government of the People\'s Republic of China (PRC) explicitly announces that Chinese citizens will be allowed to legally buy Bitcoin with yuan (renminbi) from inside China by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nFor this market to resolve to \"Yes\" it is only necessary that the PRC announces this change will take place. Whether it actually does will have no bearing on the resolution of this market.\r\n\r\nThe primary resolution source for this market will be official information from the PRC, however a consensus of credible reporting will also be used.', 1, 1, 3, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/coins/btc.svg\r\n', NULL, 1, NULL, 60.55, 0.5, 0.5, '2026-03-11 10:03:51', '2026-03-23 06:11:05'),
(58, 'CDC issues Level 3 warning by December 31?', 'cdc-issues-level-3-warning-by', 'This market will resolve to \"Yes\" if the CDC issues a Level 3 (“Reconsider Nonessential Travel”) Travel Health Notice for any disease by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nA Level 3 notice listed for any amount of time during this market’s timeframe will suffice for a \"Yes\" resolution.\r\n\r\nThe primary resolution source for this market will be the CDC’s official Travel Health Notices page (https://wwwnc.cdc.gov/travel/notices); however, a consensus of credible reporting will also be used.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-the-cdc-issue-a-level-3-warning-by-dec-31-2025-CAG97CPYu69L.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:30:41', '2026-03-23 06:10:58'),
(59, 'New COVID variant of concern before 2027?', 'new-covid-variant-of-concern-b', 'This market will resolve to \"Yes\" if the CDC identifies a new COVID variant of concern between December 1, 2025, and December 31, 2026, 11:59PM ET. Otherwise this market will resolve to \"No\".\r\n\r\nThe CDC\'s variant classification scheme can be found here: https://stacks.cdc.gov/view/cdc/107682.\r\n\r\nThe resolution source for this market will be official information from the CDC.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/human-case-of-new-covid-disease-before-april-djyPdC6Hpq6s.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:31:39', '2026-03-23 06:10:52'),
(60, 'New pandemic in 2026?', 'new-pandemic-in-2026', 'This market will resolve to \"Yes\" if the World Health Organization (WHO) declares any disease a pandemic between January 1, 2026 and December 31, 2026 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nThe resolution source will be official announcements from the World Health Organization.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/new-pandemic-in-2025-LHjGCD7X6VYI.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:32:28', '2026-03-23 06:10:45'),
(61, 'New Coronavirus Pandemic in 2026?', 'new-coronavirus-pandemic-in-20', 'This market will resolve to \"Yes\" if the World Health Organization (WHO) declares a new COVID pandemic other than COVID-19 (SARS-CoV-2) between market creation and December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nThe resolution source will be official announcements from the World Health Organization.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/new-coronavirus-pandemic-in-2025-p38YLu9s7Pws.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:33:15', '2026-03-23 06:10:38'),
(62, 'Nipah virus in US by March 31?', 'nipah-virus-in-us-by-march-31', 'This market will resolve to \"Yes\" if a confirmed human case of Nipah virus in the territory of the United States of America is reported between market creation and March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nThe primary resolution source for this market will be official government information (e.g. the CDC), however sources from NGOs like the WHO, or information from other reputable medical institutions may also be used.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/another-monkeypox-case-in-us-in-2024-AYIvG86GjWwB.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:34:12', '2026-03-23 06:10:32'),
(63, 'CDC issues Level 4 warning by December 31?', 'cdc-issues-level-4-warning-by', 'This market will resolve to \"Yes\" if the CDC issues a Level 4 (“Avoid All Travel”) Travel Health Notice for any disease by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nA Level 4 notice listed for any amount of time during this market’s timeframe will suffice for a \"Yes\" resolution.\r\n\r\nThe primary resolution source for this market will be the CDC’s official Travel Health Notices page (https://wwwnc.cdc.gov/travel/notices); however, a consensus of credible reporting will also be used.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-the-cdc-issue-a-level-3-warning-by-dec-31-2025-CAG97CPYu69L.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:34:57', '2026-03-23 06:10:25'),
(64, '10.0 or above earthquake before 2027?', '100-or-above-earthquake-befor', 'This market will resolve to “Yes” if 1 or more earthquakes with a magnitude of 10.0 or higher occur anywhere on Earth between December 8, 2025 12:00 PM ET, and December 31, 2026, 11:59PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nThe resolution source for this market is the United States Geological Survey (USGS) Earthquake Hazards Program (https://earthquake.usgs.gov/earthquakes/browse/significant.php#sigdef).\r\n\r\nIf an earthquake of substantial size has occurred within this market\'s timeframe but not yet appeared on the resolution source, this market may remain open until January 31, 2027, 11:59 PM ET, or until the earthquake in question otherwise appears on the resolution source. If such an earthquake has not appeared on the resolution source by that date, another credible resolution source will be used.\r\n\r\nAfter a qualifying earthquake is registered, this market will remain open for 24 hours to account for any revisions to its recorded magnitude. After 24 hours, this market will resolve according to the latest provided data.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/9-or-above-earthquake-before-2027.svg', NULL, 1, NULL, 1000, 0.5, 0.5, '2026-03-11 10:36:27', '2026-03-23 06:10:18'),
(65, 'Will any Category 5 hurricane make landfall in the US in before 2027?', 'will-any-category-5-hurricane', 'For the purposes of this market, a Category 5 hurricane is a hurricane with maximum sustained winds of 157 mph or higher, as described at https://www.nhc.noaa.gov/aboutsshws.php, and a hurricane landfall is said to occur when the hurricane\'s surface center intersects with the coastline, as described at https://www.nhc.noaa.gov/aboutgloss.shtml#LANDFALL.\r\n\r\nThis market will resolve to \"Yes\" if any storm makes landfall in the conterminous United States as a Category 5 hurricane, as reported in official National Hurricane Center advisories (https://www.nhc.noaa.gov/archive/2023/IDALIA.shtml?) between market creation and December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nThis market may resolve based on the initial advisory released by the NHC for whether any storm has made landfall in the conterminous United States at Category 5 strength, regardless of any later retraction or analysis that may contradict the initial qualifying announcement. However, subsequent corrections or updates will be considered if they indicate a qualifying incident.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/hurricaneida.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:37:25', '2026-03-23 06:10:11'),
(66, '9.0 or above earthquake before 2027?', '90-or-above-earthquake-before', 'This market will resolve to “Yes” if 1 or more earthquakes with a magnitude of 9.0 or higher occur anywhere on Earth between December 8, 2025 12:00 PM ET, and December 31, 2026, 11:59PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nThe resolution source for this market is the United States Geological Survey (USGS) Earthquake Hazards Program (https://earthquake.usgs.gov/earthquakes/browse/significant.php#sigdef).\r\n\r\nIf an earthquake of substantial size has occurred within this market\'s timeframe but not yet appeared on the resolution source, this market may remain open until January 31, 2027, 11:59 PM ET, or until the earthquake in question otherwise appears on the resolution source. If such an earthquake has not appeared on the resolution source by that date, another credible resolution source will be used.\r\n\r\nAfter a qualifying earthquake is registered, this market will remain open for 24 hours to account for any revisions to its recorded magnitude. After 24 hours, this market will resolve according to the latest provided data.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/9-or-above-earthquake-before-2027.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:38:22', '2026-03-23 06:10:04'),
(67, 'Will any month of 2026 be the hottest on record?', 'will-any-month-of-2026-be-the', 'This market will resolve based on the data for the Global Land-Ocean Temperature Index for any month of 2026 versus the data points available for all years for the relevant month on record. If any month of 2026 is the hottest of that month for any year in record, this market will resolve to \"Yes\". Otherwise, this market will resolve to \"No\".\r\n\r\nNote: If any month of 2026 is tied for hottest with the same month of another year, this market will resolve to \"Yes\".\r\n\r\nThe primary resolution source for this market will be the figures found in the table titled \"GLOBAL Land-Ocean Temperature Index in 0.01 degrees Celsius\" (https://data.giss.nasa.gov/gistemp/tabledata_v4/GLB.Ts+dSST.txt). If NASA\'s \"Global Temperature Index\" is rendered permanently unavailable, other information from NASA may be used.\r\n\r\nThis market may resolve immediately upon the release of data for any month which qualifies towards a \"Yes\" resolution.\r\n\r\nIf no information for all months is provided by NASA by January 31, 2027, 11:59 PM ET, a consensus of credible sources will be used to resolve this market.', 7, 9, 12, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/Will-any-month-of-2026-be-the-hottest-on-record.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:40:04', '2026-03-23 06:09:56'),
(68, 'Meta (META) Up or Down on March 30?', 'meta-meta-up-or-down-on-marc', 'This market will resolve to \"Up\" if the official NASDAQ closing price for Meta Platforms, Inc. (META) on Wednesday, March 11, 2026 is higher than the official NASDAQ closing price for META on the most recent prior trading day.\r\n\r\nThis market will resolve to \"Down\" if the official NASDAQ closing price for Meta Platforms, Inc. (META) on Wednesday, March 11, 2026 is lower than the official NASDAQ closing price for META on the most recent prior trading day.\r\n\r\nE.g., ordinarily, a market on Monday would refer to the previous Friday for its most recent closing price, unless that Friday were a market holiday, in which case it would refer to Thursday, or the next most recent trading day.\r\n\r\nIf the two specified closing prices are exactly equal, this market will resolve 50-50. Note that all figures will be rounded to the nearest cent using standard rounding.\r\n\r\nIf META does not trade at all during the regular session, the market will resolve 50-50.\r\n\r\nIf either of the relevant days are shortened (for example, due to a market holiday schedule), the official closing price published by NASDAQ for that shortened session will still be used for resolution.\r\n\r\nIf either of the relevant days have no official closing price (for example, due to a trading halt into the market close, system issue, delisting, or other disruption), the market will use the last valid on-exchange trade price of the regular session as the effective closing price.\r\n\r\nThe resolution source for this market is NASDAQ, specifically the exchange-certified Close values published at https://www.nasdaq.com/market-activity/quotes/historical.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/meta-logo-a093fc9ccc.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:46:26', '2026-03-23 06:09:50'),
(69, 'Will PDD Holdings (PDD) beat quarterly earnings?', 'will-pdd-holdings-pdd-beat-q', 'As of market creation, PDD Holdings is estimated to release earnings on March 19, 2026. The Street consensus estimate for PDD Holdings’s non-GAAP EPS for the relevant quarter is $3.06 as of market creation. This market will resolve to \"Yes\" if PDD Holdings reports non-GAAP EPS greater than $3.06 for the relevant quarter in its next quarterly earnings release. Otherwise, it will resolve to \"No.\" The resolution source will be the non-GAAP EPS listed in the company’s official earnings documents.\r\n\r\nIf PDD Holdings releases earnings without non-GAAP EPS, then the market will resolve according to the non-GAAP EPS figure reported by SeekingAlpha. If no such figure is published within 96h of market close (4:00:00pm ET) on the day earnings are announced, the market will resolve according to the GAAP EPS listed in the company’s official earnings documents; or, if not published there, according to the GAAP EPS provided by SeekingAlpha. If no GAAP EPS number is available from either source at that time, the market will resolve to “No.” (For the purposes of this market, GAAP EPS refers to diluted GAAP EPS, unless it is not published, in which case it refers to basic GAAP EPS.)\r\n\r\nIf the company does not release earnings within 45 calendar days of the estimated earnings date, this market will resolve to “No.”\r\n\r\nNote: PDD holdings trades on NASDAQ-GS in American depositary shares (ADS), with each ADS representing four ordinary shares. This market refers to earnings per ADS.\r\nNote: Subsequent restatements, corrections, or revisions made to the initially announced non-GAAP EPS figure will not qualify for resolution, except in the case of obvious and immediate mistakes (e.g., fat finger errors, as with Lyft\'s (LYFT) earnings release in February 2024).\r\nNote: The strike prices used in these markets are derived from SeekingAlpha estimates, and reflect the consensus of sell-side analyst estimates for non-GAAP EPS.\r\nNote: All figures will be rounded to the nearest cent using standard rounding.\r\nNote: For the purposes of this market, IFRS EPS will be treated as GAAP EPS.\r\nNote: If multiple versions of non-GAAP EPS are published, the market will resolve according to the primary headline non-GAAP EPS number, which is typically presented on a diluted basis. If diluted is not published, then basic non-GAAP EPS will qualify.\r\nNote: All figures are expressed in USD, unless otherwise indicated.\r\nNote: For primarily internationally listed companies, this market refers specifically to the shares traded in the United States on U.S. stock exchanges such as the NYSE or Nasdaq. In cases where the company trades in the U.S. through an American Depositary Receipt (ADR) or American Depositary Share (ADS), this market will refer to the ADR/ADS.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/pdd-quarterly-earnings-nongaap-eps-03-19-2026-3pt06-B393aADigRqV.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:48:13', '2026-03-23 06:09:43'),
(70, 'Will Stripe acquire any part of Paypal in 2026?', 'will-stripe-acquire-any-part-o', 'This market will resolve to \"Yes\" if it is officially announced that any part of PayPal will be, has been, or is being acquired by Stripe, or that PayPal is being merged with Stripe, by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nAcquiring a part of PayPal refers to any material acquisition of a subset of PayPal by Stripe, including but not limited to a PayPal subsidiary, business unit, or equity interest. A total acquisition of PayPal by Stripe will count. Business partnerships between PayPal and Stripe will not count.\r\n\r\nAn announcement of a qualifying acquisition or merger by PayPal or PayPal and Stripe will qualify for a \"Yes\" resolution, regardless of whether the announced acquisition/merger actually occurs.\r\n\r\nThe primary resolution source for this market will be official information from PayPal and Stripe, however a consensus of credible reporting may also be used.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-stripe-acquire-paypal-in-2026--gGYjppHStfU.svg', NULL, 1, NULL, NULL, 0.5, 0.5, '2026-03-11 10:49:48', '2026-03-23 06:09:36'),
(71, 'Will Coingecko be acquired in 2026?', 'will-coingecko-be-acquired-in', 'This market will resolve to “Yes” if credible reporting confirms that any entity enters into an agreement to acquire the listed company by December 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nMergers where the listed company is subsumed by another entity will count toward a \"Yes\" resolution.\r\n\r\nAn announced agreement between the listed company and an acquiring entity will qualify for a “Yes” resolution, regardless of whether the acquisition is ultimately completed.\r\n\r\nThe primary resolution source for this market is official information from the listed company and/or its leadership; however, a consensus of credible reporting will also be used.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-coingecko-be-acquired-in-2026-dISSmm30lAqk.svg', NULL, 1, NULL, 21.98, 0.5, 0.5, '2026-03-11 10:50:46', '2026-03-23 06:09:29'),
(72, 'Trump Media x TAE Technologies merger closed by March 31?', 'trump-media-x-tae-technologies', 'Donald Trump’s Social Media and Cryptocurrency company Trump Media and Technology Group and the fusion power company TAE Technologies announced they had agreed to a merger deal on December 18th, signaling a shift of focus for the Trump-owned firm. You can read more about that here: https://www.nytimes.com/2025/12/18/business/trump-media-tae-technologies-fusion-power-deal.html\r\n\r\nThis market will resolve to “Yes” if the merger between Trump Media and Technology Group and TAE Technologies is completed by March 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to “No”.\r\n\r\nThe merger will be considered completed once it has become legally effective and the two companies are now a single entity or they exist under a single entity as one corporate group, as evidenced by official company announcements and/or regulatory filings (e.g. the filing of an 8-K form to the SEC that announces the closure of the deal). Shareholder approval, receipt of regulatory approvals, regulatory filings which do not announce the closure of the deal, or other intermediate steps towards the closing of a deal will not alone be sufficient for a ‘Yes’ resolution.\r\n\r\nIf the merger agreement is officially terminated or the deal has been abandoned according to official company communications, this market will resolve to “No”.\r\n\r\nResolution will be based on official company communications and regulatory filings from Trump Media and Technology Group, TAE Technologies, or a combined successor entity, supplemented as needed by a consensus of reporting from major reputable news outlets.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/trump-media-x-tae-technologies-merger-closed-by-march-31-l94WyfQ73hCE.svg', NULL, 1, NULL, 4.3, 0.5, 0.5, '2026-03-11 10:51:58', '2026-03-23 06:09:23'),
(73, 'How high will 10-year Treasury yield go before 2027?', 'how-high-will-10-year-treasury', 'This market will resolve to \"Yes\" if the Treasury 10-year yield reaches or is higher than the listed value for any date between December 9, 2025 and December 31, 2026. Otherwise this market will resolve to \"No\".\r\n\r\nThe resolution source for this market is the Department of the treasury, specially the data listed under \"Daily Treasury Par Yield Curve Rates\" for the column \"10 Yr\" (see: https://home.treasury.gov/resource-center/data-chart-center/interest-rates/TextView?type=daily_treasury_yield_curve&field_tdr_date_value=2025).', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/how-high-will-10-year-treasury-yield-go-in-2025-nKj-Uvwxqu0s.svg', NULL, 1, NULL, 20.46, 0.5, 0.5, '2026-03-11 10:56:05', '2026-03-23 06:09:16'),
(75, 'Will Adobe (ADBE) beat quarterly earnings?', 'will-adobe-adbe-beat-quarter', 'As of market creation, Adobe is estimated to release earnings on March 12, 2026. The Street consensus estimate for Adobe’s non-GAAP EPS for the relevant quarter is $5.87 as of market creation. This market will resolve to \"Yes\" if Adobe reports non-GAAP EPS greater than $5.87 for the relevant quarter in its next quarterly earnings release. Otherwise, it will resolve to \"No.\" The resolution source will be the non-GAAP EPS listed in the company’s official earnings documents.\r\n\r\nIf Adobe releases earnings without non-GAAP EPS, then the market will resolve according to the non-GAAP EPS figure reported by SeekingAlpha. If no such figure is published within 96h of market close (4:00:00pm ET) on the day earnings are announced, the market will resolve according to the GAAP EPS listed in the company’s official earnings documents; or, if not published there, according to the GAAP EPS provided by SeekingAlpha. If no GAAP EPS number is available from either source at that time, the market will resolve to “No.” (For the purposes of this market, GAAP EPS refers to diluted GAAP EPS, unless it is not published, in which case it refers to basic GAAP EPS.)\r\n\r\nIf the company does not release earnings within 45 calendar days of the estimated earnings date, this market will resolve to “No.”\r\n\r\nNote: Subsequent restatements, corrections, or revisions made to the initially announced non-GAAP EPS figure will not qualify for resolution, except in the case of obvious and immediate mistakes (e.g., fat finger errors, as with Lyft\'s (LYFT) earnings release in February 2024).\r\nNote: The strike prices used in these markets are derived from SeekingAlpha estimates, and reflect the consensus of sell-side analyst estimates for non-GAAP EPS.\r\nNote: All figures will be rounded to the nearest cent using standard rounding.\r\nNote: For the purposes of this market, IFRS EPS will be treated as GAAP EPS.\r\nNote: If multiple versions of non-GAAP EPS are published, the market will resolve according to the primary headline non-GAAP EPS number, which is typically presented on a diluted basis. If diluted is not published, then basic non-GAAP EPS will qualify.\r\nNote: All figures are expressed in USD, unless otherwise indicated.\r\nNote: For primarily internationally listed companies, this market refers specifically to the shares traded in the United States on U.S. stock exchanges such as the NYSE or Nasdaq. In cases where the company trades in the U.S. through an American Depositary Receipt (ADR) or American Depositary Share (ADS), this market will refer to the ADR/ADS', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/adbe-quarterly-earnings-nongaap-eps-03-12-2026-5pt87-RMD5zrToZbtM.svg', NULL, 1, NULL, 4, 0.5, 0.5, '2026-03-11 10:58:04', '2026-03-23 06:09:09'),
(76, 'Will Playboy (PLBY) beat quarterly earnings?', 'will-playboy-plby-beat-quart', 'As of market creation, Playboy is estimated to release earnings on March 12, 2026. The Street consensus estimate for Playboy\'s GAAP EPS for the relevant quarter is $0.01 as of market creation. This market will resolve to \"Yes\" if Playboy reports GAAP EPS greater than $0.01 for the relevant quarter in its next quarterly earnings release. Otherwise, it will resolve to \"No.\" The resolution source will be the GAAP EPS listed in the company’s official earnings documents.\r\n\r\nIf Playboy releases earnings without GAAP EPS, then the market will resolve according to the GAAP EPS figure reported by SeekingAlpha. If no such figure is published within 96h of market close (4:00:00pm ET) on the day earnings are announced, the market will resolve to “No”.\r\n\r\nIf the company does not release earnings within 45 calendar days of the estimated earnings date, this market will resolve to “No.”\r\n\r\nNote: Subsequent restatements, corrections, or revisions made to the initially announced GAAP EPS figure will not qualify for resolution, except in the case of obvious and immediate mistakes (e.g., fat finger errors, as with Lyft\'s (LYFT) earnings release in February 2024).\r\nNote: The strike prices used in these markets are derived from SeekingAlpha estimates, and reflect the consensus of sell-side analyst estimates for GAAP EPS.\r\nNote: All figures will be rounded to the nearest cent using standard rounding.\r\nNote: For the purposes of this market, IFRS EPS will be treated as GAAP EPS.\r\nNote: For the purposes of this market, GAAP EPS refers to diluted GAAP EPS, unless this is not published, in which case it refers to basic GAAP EPS.\r\nNote: All figures are expressed in USD, unless otherwise indicated.\r\nNote: For primarily internationally listed companies, this market refers specifically to the shares traded in the United States on U.S. stock exchanges such as the NYSE or Nasdaq. In cases where the company trades in the U.S. through an American Depositary Receipt (ADR) or American Depositary Share (ADS), this market will refer to the ADR/ADS.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/plby-quarterly-earnings-gaap-eps-03-12-2026-0pt01-jk_905QJ3fJY.svg', NULL, 1, NULL, 4.1, 0.5, 0.5, '2026-03-11 10:59:06', '2026-03-23 06:09:02'),
(77, 'Another US bank failure by March 31?', 'another-us-bank-failure-by-mar', 'This market will resolve to \"Yes\" if any US bank fails between this market\'s creation and the listed date 11:59 PM ET (according to the FDIC\'s \"Failed Bank List\"). Otherwise, this market will resolve to \"No.\"\r\n\r\nFor this market to resolve to \"Yes\", the bank\'s closing date as listed by the FDIC must be within this market\'s above-specified timeframe. If there is a potential bank failure within this market\'s timeframe and the FDIC \"Failed Bank List\" has not been updated yet, this market may remain open to allow for the list to be updated.\r\n\r\nThe primary resolution source for this market will be the Federal Deposit Insurance Corporation (FDIC), specifically the \"Failed Bank List\" available here: https://www.fdic.gov/resources/resolutions/bank-failures/failed-bank-list/; however, other official statements from the FDIC and government entities will suffice.', 8, 10, 13, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/us-bank-failure-before-july-qD-OyV8GYFks.svg', NULL, 1, NULL, 44, 0.5, 0.5, '2026-03-11 11:01:33', '2026-03-23 06:08:55'),
(78, 'Will Lady Gaga attend the Met Gala?', 'will-lady-gaga-attend-the-met', 'The 2026 Met Gala is scheduled for May 4, 2026. This year\'s theme is \"Costume Art\".\r\n\r\nThis market will resolve to \"Yes\" if Lady Gaga attends the 2026 Met Gala. Otherwise, this market will resolve to \"No\".\r\n\r\nIf the event is canceled or postponed beyond May 31, 2026, 11:59 PM ET, this market will resolve to \"No\".\r\n\r\nAttending the event is defined as being in physical attendance during any part of the event.\r\n\r\nThe resolution source will be a consensus of credible reporting.', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question\r\n/will-lady-gaga-attend-the-met-gala.svg', NULL, 1, 9, 22, 0.5, 0.5, '2026-03-11 11:15:31', '2026-03-23 06:08:48'),
(79, 'Will George R. R. Martin announce \"The Winds of Winter\" in 2026?', 'will-george-r-r-martin-annou', 'This market will resolve to \"Yes\" if George R. R. Martin publicly and explicitly announces by December 31, 2026, 11:59 PM ET that an installment of A Song of Ice and Fire titled \"The Winds of Winter\" will be released. Otherwise, this market will resolve to \"No\".\r\n\r\nThe announcement of the creation of any expansion or sequel not explicitly named \"The Winds of Winter\" (e.g., Fire & Blood, A Sworn Sword) will not be sufficient to qualify this market toward a \"Yes\" resolution. The book must have the words \"The Winds of Winter\" in the title to qualify. This market is concerned only with the announcement of release.\r\n\r\nThe resolution source for this market will be official information from George R. R. Martin or a consensus of credible sources.', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/will-george-r-r-martin-announce-the-winds-of-winter-before-2027-FTx2egxxBqhU.svg', NULL, 1, NULL, 12.4, 0.5, 0.5, '2026-03-11 11:17:17', '2026-03-23 06:08:41');
INSERT INTO `prediction_markets` (`id`, `question`, `slug`, `rules`, `category_id`, `subcategory_id`, `condition_id`, `start_range_value`, `end_range_value`, `start_time`, `end_time`, `status`, `winning_outcome`, `trading_fee_percent`, `image`, `auto_generate_frequency`, `auto_generate_frequency_status`, `crypto_coin_id`, `tot_traded_val`, `last_yes_price`, `last_no_price`, `created_at`, `updated_at`) VALUES
(80, 'Will MrBeast get married by December 31?', 'will-mrbeast-get-married-by-de', 'This market will resolve to \"Yes\" if Jimmy Donaldson\'s (aka MrBeast) marriage takes place by December 31, 2026, 11:59 PM. Otherwise, this market will resolve to \"No\".\r\n\r\nOnly announcements made within this market\'s timeframe will qualify. No announcements made after December 31, 2026, 11:59PM ET will be considered, even if the marriage itself is announced to have taken place within the market\'s timeframe.\r\n\r\nThe primary resolution source for this market will be information from MrBeast, however a consensus of credible reporting will also be used.', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/of-views-of-next-mrbeast-video-on-day-1--HcOnJGLLP3O.svg', NULL, 1, NULL, 943.5, 0.5, 0.5, '2026-03-11 11:18:41', '2026-03-23 06:08:34'),
(81, '100m views on a MrBeast video in the first week by March 31?', '100m-views-on-a-mrbeast-video', 'This market will resolve to \"Yes\" if the number of views any YouTube video posted by MrBeast gets in the first 7 days after being posted is greater than or equal to 100 million by March 31, 2026, 11:59PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nIf MrBeast does not post a YouTube video by March 31, 2026, 11:59 PM ET, this market will resolve to \"No\".\r\n\r\nThe resolution source for this is MrBeast\'s YouTube channel (https://www.youtube.com/@MrBeast), specifically the \'views\' counter for the described video.', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/of-views-of-next-mrbeast-video-on-day-1--HcOnJGLLP3O.svg', NULL, 1, NULL, 117.1, 0.5, 0.5, '2026-03-11 11:19:34', '2026-03-23 06:08:28'),
(82, 'GTA 6 launch postponed again?', 'gta-6-launch-postponed-again', 'On November 6, 2025, Take-Two Interactive, the parent company of Rockstar Games, announced that the launch of Grand Theft Auto VI (GTA VI) would be postponed from its previously scheduled release date of May 26, 2026, to a new release date of November 19, 2026.\r\n\r\nThis market will resolve to \"Yes\" if by November 19, 2026, 11:59 PM ET, Rockstar Games or its parent company, Take-Two Interactive, officially announces that Grand Theft Auto VI will not be released by November 19, 2026, or if Grand Theft Auto VI is otherwise not released in the US by November 19, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nFor the purposes of this market, \"release\" refers to the game becoming publicly available for purchase or download in the US. Early access, beta versions, other forms of pre-release availability, or leaks will not count as an official release. If the release is only for certain consoles (e.g. Xbox Series X/S) it will count.\r\n\r\nThe resolution source will be official information from Rockstar Games or its parent company, Take-Two Interactive; however a consensus of credible reporting may also be used.', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/gta-vi-released-before-june-2026-igCgZsDMejF.svg', NULL, 1, NULL, 409.95, 0.5, 0.5, '2026-03-11 11:22:35', '2026-03-23 07:09:04'),
(83, 'GTA VI released before June 2026?', 'gta-vi-released-before-june-20', 'This market will resolve to \"Yes\" if it Grand Theft Auto VI is officially released in the US by May 31, 2026, 11:59 PM ET. Otherwise, this market will resolve to \"No\".\r\n\r\nFor the purposes of this market, \"release\" refers to the game becoming publicly available for purchase or download in the US. Early access, beta versions, other forms of pre-release availability, or leaks will not count as an official release. If the release is only for certain consoles (e.g. Xbox Series X/S) it will count.\r\n\r\nThe resolution source will be official information from Rockstar Games or its parent company, Take-Two Interactive', 9, 11, 14, NULL, NULL, NULL, NULL, 'open', NULL, 1.00, 'uploads/question/gta-vi-released-before-june-2026-igCgZsDMejF.svg', NULL, 1, NULL, 346.91, 0.5, 0.5, '2026-03-11 11:23:38', '2026-03-23 07:08:57'),
(85, 'Up or Down on ETH in next 24 hours?', 'eth-updown-daily-1773842051', 'If the price of ETH is above  after 24 hours, \'Yes\' wins. If it is below, \'No\' wins. Results will be based on the price at 2026-03-19 00:00:00. Winning result based on the Bybit price feed.', 3, 2, 6, NULL, 2240, '2026-03-18 13:54:11', '2026-03-19 00:00:00', 'open', NULL, 1.00, 'uploads/coins/eth.svg', 'daily', 1, 2, 20.5, 0.5, 0.5, '2026-03-18 13:54:11', '2026-03-23 07:08:49'),
